proof fn phi_1_serialize_injective_without_marshalable(a: usize, b: usize)
    requires
        !a.is_marshalable(),
        !b.is_marshalable(),
        a.ghost_serialize() == b.ghost_serialize(),
    ensures
        a.view_equal(&b),
{
    a.lemma_serialize_injective(&b);
}

proof fn phi_5_tuple_serialize_prefix_ambiguity(a1: u64, a2: Vec<u8>, b1: u64, b2: Vec<u8>)
    requires
        (a1, a2).is_marshalable(),
        (b1, b2).is_marshalable(),
        (a1, a2).ghost_serialize() == (b1, b2).ghost_serialize(),
    ensures
        a1.ghost_serialize() == b1.ghost_serialize(),
{
    (a1, a2).lemma_serialize_injective(&(b1, b2));
}
